class Solution:
    def countOfSubstrings(self, word, k):
        VOWELS = set('aeiou')
        n = len(word)
        total = 0
        for i in range(n):
            cons = 0
            seen = set()
            for j in range(i, n):
                c = word[j]
                if c in VOWELS:
                    seen.add(c)
                else:
                    cons += 1
                if len(seen) == 5 and cons == k:
                    total += 1
        return total

