class Solution:
    def countOfSubstrings(self, word, k):
        VOWELS = set('aeiou')

        def at_most(limit):
            if limit < 0:
                return 0
            n = len(word)
            left1 = 0
            cons1 = 0
            left2 = 0
            vcount = {v: 0 for v in VOWELS}
            distinct = 0
            total = 0
            for right in range(n):
                c = word[right]
                if c not in VOWELS:
                    cons1 += 1
                while cons1 > limit:
                    if word[left1] not in VOWELS:
                        cons1 -= 1
                    left1 += 1
                if c in VOWELS:
                    vcount[c] += 1
                    if vcount[c] == 1:
                        distinct += 1
                while distinct == 5:
                    lc = word[left2]
                    if lc in VOWELS:
                        if vcount[lc] == 1:
                            break
                        vcount[lc] -= 1
                    left2 += 1
                if distinct == 5 and left2 >= left1:
                    total += left2 - left1 + 1
            return total

        return at_most(k) - at_most(k - 1)

