var countOfSubstrings = function(word, k) {
    const VOWELS = new Set(['a', 'e', 'i', 'o', 'u']);
    function atMost(limit) {
        if (limit < 0) return 0;
        const n = word.length;
        let left1 = 0, cons1 = 0, left2 = 0, distinct = 0, total = 0;
        const vcount = { a: 0, e: 0, i: 0, o: 0, u: 0 };
        for (let right = 0; right < n; right++) {
            const c = word[right];
            if (!VOWELS.has(c)) cons1++;
            while (cons1 > limit) {
                if (!VOWELS.has(word[left1])) cons1--;
                left1++;
            }
            if (VOWELS.has(c)) {
                vcount[c]++;
                if (vcount[c] === 1) distinct++;
            }
            while (distinct === 5) {
                const lc = word[left2];
                if (VOWELS.has(lc)) {
                    if (vcount[lc] === 1) break;
                    vcount[lc]--;
                }
                left2++;
            }
            if (distinct === 5 && left2 >= left1) {
                total += left2 - left1 + 1;
            }
        }
        return total;
    }
    return atMost(k) - atMost(k - 1);
};
